class IoTDeviceController:
    def __init__(self, pin_control=None):
        self.state = {
            "power": False,
            "last_action": "init",
            "timestamp": utime.time()
        }
        self.pin_control = pin_control

    def update_timestamp(self):
        self.state["timestamp"] = utime.time()

    def turn_on(self):
        self.state["power"] = True
        self.state["last_action"] = "turn_on"
        self.update_timestamp()
        if self.pin_control:
            self.pin_control(1)
        return {"ok": True, "state": self.state}

    def turn_off(self):
        self.state["power"] = False
        self.state["last_action"] = "turn_off"
        self.update_timestamp()
        if self.pin_control:
            self.pin_control(0)
        return {"ok": True, "state": self.state}

    def get_status(self):
        self.state["last_action"] = "status"
        self.update_timestamp()
        return {"ok": True, "state": self.state}

    def handle(self, message):
        try:
            obj = ujson.loads(message)
        except Exception:
            return {"ok": False, "error": "invalid_json"}

        action = obj.get("action")
        if action == "turn_on":
            return self.turn_on()
        elif action == "turn_off":
            return self.turn_off()
        elif action == "status":
            return self.get_status()
        else:
            return {"ok": False, "error": "unknown_action", "action": action}


class WebSocketServer:
    def __init__(self, host="0.0.0.0", port=8080, controller=None):
        self.host = host
        self.port = port
        self.controller = controller or IoTDeviceController()
        self.server_sock = None

    def read_http_request(self, client):
        data = b""
        while b"\r\n\r\n" not in data:
            chunk = client.recv(512)
            if not chunk:
                break
            data += chunk
            if len(data) > 4096:
                break
        return data.decode()

    def parse_headers(self, request):
        lines = request.split("\r\n")
        if not lines or "GET" not in lines[0]:
            return None, None, None

        path = lines[0].split(" ")[1]
        headers = {}
        for line in lines[1:]:
            if not line:
                continue
            if ":" in line:
                k, v = line.split(":", 1)
                headers[k.strip().lower()] = v.strip()
        return lines[0], path, headers

    def send_http_response(self, client, status, content_type, body):
        if isinstance(body, str):
            body = body.encode()
        resp = (
            "HTTP/1.1 " + status + "\r\n"
            "Content-Type: " + content_type + "\r\n"
            "Content-Length: " + str(len(body)) + "\r\n"
            "Connection: close\r\n"
            "\r\n"
        )
        client.send(resp.encode())
        client.send(body)

